import{_ as t,H as a,f as o,i as r}from"./chunks/framework.nN4pLK1d.js";const p=JSON.parse('{"title":"Interface: EmailThemePatch","description":"","frontmatter":{},"headers":[],"relativePath":"api/rcml/src/interfaces/EmailThemePatch.md","filePath":"api/rcml/src/interfaces/EmailThemePatch.md"}'),l={name:"api/rcml/src/interfaces/EmailThemePatch.md"};function s(c,e,i,n,d,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../../../"><strong>Rule.io SDK</strong></a></p><hr><p><a href="./../../../">Rule.io SDK</a> / <a href="./../">rcml/src</a> / EmailThemePatch</p><h1>Interface: EmailThemePatch</h1><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/dd48e7732354158de19f6a968d2bc027cee71f07/packages/rcml/src/email/theme-types.ts#L205" target="_blank" rel="noreferrer">rcml/src/email/theme-types.ts:205</a></p><p>A partial-theme shape used by two call sites:</p><ul><li><code>createEmailTheme</code> — seed values applied on top of the defaults when constructing a fresh theme.</li><li><code>applyTheme</code> — a patch written into an existing rcml document; only the buckets present in the patch are touched.</li></ul><p>Each bucket uses arrays (not the full <code>EmailTheme</code> map shape) so a caller can write <code>{ colors: [{ type: Primary, hex: &#39;#F00&#39; }] }</code> without restating the slot key. <code>fontStyles</code> accepts entry-level partials so <code>{ type: H1, color: &#39;#F00&#39; }</code> changes just the colour and keeps the rest of the slot at its default.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="brandstyleid" tabindex="-1">brandStyleId? <a class="header-anchor" href="#brandstyleid" aria-label="Permalink to &quot;brandStyleId?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>brandStyleId?</strong>: <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/dd48e7732354158de19f6a968d2bc027cee71f07/packages/rcml/src/email/theme-types.ts#L207" target="_blank" rel="noreferrer">rcml/src/email/theme-types.ts:207</a></p><p>Numeric brand-style id to set on <code>&lt;rc-brand-style&gt;</code>.</p><hr><h3 id="colors" tabindex="-1">colors? <a class="header-anchor" href="#colors" aria-label="Permalink to &quot;colors?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>colors?</strong>: <a href="./EmailThemeColor.html"><code>EmailThemeColor</code></a>[]</p></blockquote><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/dd48e7732354158de19f6a968d2bc027cee71f07/packages/rcml/src/email/theme-types.ts#L209" target="_blank" rel="noreferrer">rcml/src/email/theme-types.ts:209</a></p><p>Colour entries keyed by slot type; unspecified slots fall back to defaults.</p><hr><h3 id="fonts" tabindex="-1">fonts? <a class="header-anchor" href="#fonts" aria-label="Permalink to &quot;fonts?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>fonts?</strong>: <a href="./EmailThemeFont.html"><code>EmailThemeFont</code></a>[]</p></blockquote><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/dd48e7732354158de19f6a968d2bc027cee71f07/packages/rcml/src/email/theme-types.ts#L215" target="_blank" rel="noreferrer">rcml/src/email/theme-types.ts:215</a></p><p>Ordered fonts list; an empty array clears every font registration.</p><hr><h3 id="fontstyles" tabindex="-1">fontStyles? <a class="header-anchor" href="#fontstyles" aria-label="Permalink to &quot;fontStyles?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>fontStyles?</strong>: <code>Partial</code>&lt;<a href="./EmailThemeFontStyle.html"><code>EmailThemeFontStyle</code></a>&gt;[]</p></blockquote><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/dd48e7732354158de19f6a968d2bc027cee71f07/packages/rcml/src/email/theme-types.ts#L221" target="_blank" rel="noreferrer">rcml/src/email/theme-types.ts:221</a></p><p>Per-slot partial font-style overrides. Missing fields on an override fall back to the slot&#39;s default, so <code>{ type: H1, color: &#39;#F00&#39; }</code> changes only the colour and keeps size/weight/family at defaults.</p><hr><h3 id="images" tabindex="-1">images? <a class="header-anchor" href="#images" aria-label="Permalink to &quot;images?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>images?</strong>: <a href="./EmailThemeImage.html"><code>EmailThemeImage</code></a>[]</p></blockquote><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/dd48e7732354158de19f6a968d2bc027cee71f07/packages/rcml/src/email/theme-types.ts#L213" target="_blank" rel="noreferrer">rcml/src/email/theme-types.ts:213</a></p><p>Image entries keyed by slot type; an empty array clears all images.</p><hr><h3 id="links" tabindex="-1">links? <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>links?</strong>: <a href="./EmailThemeSocialLink.html"><code>EmailThemeSocialLink</code></a>[]</p></blockquote><p>Defined in: <a href="https://github.com/rulecom/rule-io-sdk/blob/dd48e7732354158de19f6a968d2bc027cee71f07/packages/rcml/src/email/theme-types.ts#L211" target="_blank" rel="noreferrer">rcml/src/email/theme-types.ts:211</a></p><p>Social-link entries keyed by slot type; unspecified slots fall back to defaults.</p>',38)])])}const f=t(l,[["render",s]]);export{p as __pageData,f as default};
